settings.custom_css:
.vm-heading {
  font-family: "Inter", "Space Grotesk", system-ui, -apple-system, sans-serif;
}

/* Space Grotesk words */
.font-space {
  font-family: "Space Grotesk", "Inter", system-ui, sans-serif;
}

/* Inter words */
.font-inter {
  font-family: "Inter", "Space Grotesk", system-ui, sans-serif;
}

.section * {
  box-sizing: border-box;
}

..section {
  width: 100%;
  max-width: 1400px;
  margin: 0 auto;
  padding: 3rem 1.5rem;
  background: #ffffff !important; /* ← critical */
}

.cards {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 20px;
  background: #d9d5ce;
  border: 1px solid #d9d5ce;
}

.card {
  background: #ffffff;
  padding: 4rem 3rem;
  min-height: 450px;
  position: relative;
  overflow: hidden;
  transition: background 0.4s ease;
}

.card:hover {
  background: #fafafa;
}

.card-icon {
  width: 64px;
  height: 64px;
  margin-bottom: 2rem;
  opacity: 0.85;
}

.card-heading {
  font-family: 'Inter', sans-serif;
  font-size: clamp(2.2rem, 3vw, 3rem);
  font-weight: 400;
  letter-spacing: -0.005em;
  line-height: 1.2;
  margin-bottom: 1.1rem;
  color: #1a1916;
}

.card-divider {
  width: 32px;
  height: 1px;
  background: #c9a96e;
  margin-bottom: 1.25rem;
  transition: width 0.4s ease;
}

.card:hover .card-divider {
  width: 56px;
}

.card-text {
  font-size: 1.2rem;
  font-weight: 300;
  line-height: 1.9;
  color: #7a7770;
  max-width: 38ch;
}

.card::after {
  content: '';
  position: absolute;
  bottom: 1.5rem;
  right: 1.5rem;
  width: 6px;
  height: 6px;
  border-right: 1px solid #d9d5ce;
  border-bottom: 1px solid #d9d5ce;
}

@media (max-width: 640px) {
  .cards {
    grid-template-columns: 1fr;
  }

  .card {
    padding: 2.5rem 1.75rem 3rem;
  }

  .card-text {
    max-width: 100%;
  }
}
.cards,
.card {
  background: #ffffff !important;
}
